#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;

    // darken (decay) over uTime
    ret *= 0.99; //or try: ret -= 0.004;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


 // This preset is intended to produce a single mobile point light to illuminate a generated, normal and depth
 // mapped image that incorporates an eight way mirror effect.  The point light must have a visible sprite and
 // that sprite must be light color apropriate, and it should scale properly in response to location and brightness




 // First we find the average of the x & y for each of our pixels, this lets us test to see which quarter of
 //   the screen we are in when you divide it up from corner to corner.  along the diagonal from 0,0 to 1,1,
 //   x = y, and along the other diagonal, (x + y) / 2 = .5... so we precompute for efficiency:
    float non_ave = float((vUv.x + vUv.y)* 0.5);
    float lat_ave = float((vUv.x + uTexSize.z + vUv.y)* 0.5);
    float vrt_ave = float((vUv.x + vUv.y + uTexSize.w)* 0.5);

 // create 3 vUv pairs; non, for the non-shifted pixel, lat, for the pixel shifted in x and vrt for the y-shifted one
    vec2 non_final = vUv;
    vec2 lat_final = vec2(vUv.x + uTexSize.z, vUv.y);
    vec2 vrt_final = vec2(vUv.x, vUv.y + uTexSize.w);

 // Now we flip and flop each of our three uvs around to give us a total of 8 possible uvs per pixel
    vec2 non_one = non_final.yx;
    vec2 lat_one = lat_final.yx;
    vec2 vrt_one = vrt_final.yx;
    vec2 non_two = non_one * vec2(-1, 1);
    vec2 lat_two = lat_one * vec2(-1, 1);
    vec2 vrt_two = vrt_one * vec2(-1, 1);
    vec2 non_three = non_two.yx;
    vec2 lat_three = lat_two.yx;
    vec2 vrt_three = vrt_two.yx;
    vec2 non_four = non_three * vec2(-1, 1);
    vec2 lat_four = lat_three * vec2(-1, 1);
    vec2 vrt_four = vrt_three * vec2(-1, 1);
    vec2 non_five = non_four.yx;
    vec2 lat_five = lat_four.yx;
    vec2 vrt_five = vrt_four.yx;
    vec2 non_six = non_five * vec2(-1, 1);
    vec2 lat_six = lat_five * vec2(-1, 1);
    vec2 vrt_six = vrt_five * vec2(-1, 1);
    vec2 non_seven = non_six.yx;
    vec2 lat_seven = lat_six.yx;
    vec2 vrt_seven = vrt_six.yx;

 // Next we decide which of our 24 uvs we should use for each of our 3 pixels
    if (non_ave < 0.5 && non_final.x < 0.5 && non_final.y < 0.5 && non_final.x < non_final.y){non_final = non_one;}
    if (lat_ave < 0.5 && lat_final.x < 0.5 && lat_final.y < 0.5 && lat_final.x < lat_final.y){lat_final = lat_one;}
    if (vrt_ave < 0.5 && vrt_final.x < 0.5 && vrt_final.y < 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_one;}
    if (non_ave < 0.5 && non_final.x < 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_two;}
    if (lat_ave < 0.5 && lat_final.x < 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_two;}
    if (vrt_ave < 0.5 && vrt_final.x < 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_two;}
    if (non_ave > 0.5 && non_final.x < 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_three;}
    if (lat_ave > 0.5 && lat_final.x < 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_three;}
    if (vrt_ave > 0.5 && vrt_final.x < 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_three;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y > 0.5 && non_final.x < non_final.y){non_final = non_four;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y > 0.5 && lat_final.x < lat_final.y){lat_final = lat_four;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y > 0.5 && vrt_final.x < vrt_final.y){vrt_final = vrt_four;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y > 0.5 && non_final.x > non_final.y){non_final = non_five;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y > 0.5 && lat_final.x > lat_final.y){lat_final = lat_five;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y > 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_five;}
    if (non_ave > 0.5 && non_final.x > 0.5 && non_final.y < 0.5 && non_final.x > non_final.y){non_final = non_six;}
    if (lat_ave > 0.5 && lat_final.x > 0.5 && lat_final.y < 0.5 && lat_final.x > lat_final.y){lat_final = lat_six;}
    if (vrt_ave > 0.5 && vrt_final.x > 0.5 && vrt_final.y < 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_six;}
    if (non_ave < 0.5 && non_final.x > 0.5 && non_final.y < 0.5 && non_final.x > non_final.y){non_final = non_seven;}
    if (lat_ave < 0.5 && lat_final.x > 0.5 && lat_final.y < 0.5 && lat_final.x > lat_final.y){lat_final = lat_seven;}
    if (vrt_ave < 0.5 && vrt_final.x > 0.5 && vrt_final.y < 0.5 && vrt_final.x > vrt_final.y){vrt_final = vrt_seven;}

 // Now we get the RGB values for each of our three pixels using the correct UVs
    vec3 non = texture(sampler_main, non_final).xyz;
    vec3 lat = texture(sampler_main, lat_final).xyz;
    vec3 vrt = texture(sampler_main, vrt_final).xyz;

 // Finding the brightness for each pixel (not the luminance)
    float nonHeight = (non.x + non.y + non.z);//*0.33333333;
    float latHeight = (lat.x + lat.y + lat.z);//*0.33333333;
    float vrtHeight = (vrt.x + vrt.y + vrt.z);//*0.33333333;
    float Height = (non.x + non.y + non.z) * 0.5;

 // Comparing the brightness of the pixels to build a 2D vector in the x,y plane & normalizing it
    vec2 XYVec = vec2(nonHeight - latHeight, nonHeight - vrtHeight);
    float XYVecLen = length(XYVec);
    if (XYVecLen > 1.0){normalize(XYVec);}

 // Using Pythagoras to generate 3D vector
    float Z = sqrt(1 - (pow(XYVec.x, 2) + pow(XYVec.y, 2)));
    vec3 normal = vec3(XYVec.x, XYVec.y, Z);// -1.0 to 1.0 ranged for computation
    XYVec.x = (XYVec.x + 1.0) * 0.5;
    XYVec.y = (XYVec.y + 1.0) * 0.5;
    vec3 disp_normal = vec3(XYVec.x, XYVec.y, Z);// 0 to 1.0 ranged for screen display
 // generate the difuse color for this pixel
    vec3 diffuse = texture(sampler_main, non_final).xyz;
    diffuse *= 1.00; //gamma
    diffuse = sqrt(diffuse); //brighten
    diffuse *= diffuse; //darken

 // Setting up the camera position
    vec3 camera_vector = vec3(0.5, 0.5, 2.5);

 // rendering the point light
    //Notes:  using a total depth range of 0 to 4 with texture occupying 0.0 to 1.5 range
    // First draw the point, then worry about making it look good.
    //
    vec3 this_texel = vec3(vUv.x, vUv.y, Height);
    vec3 point_color = vec3(q8, q9, q10);
    vec3 point_location = vec3(q5, q6, q7);
    float dist_2_point = sqrt(pow((this_texel.x - point_location.x), 2) + pow((this_texel.y - point_location.y), 2)
                                             + pow((this_texel.z - point_location.z), 2));
    float point_scale = q11;//.85 - q31;//0.650;
    vec3 point_falloff = vec3(0, 0, 0);
    float undispersed = 1.0 - dist_2_point / point_scale;
    if (dist_2_point <= point_scale){point_falloff = point_color * undispersed;}

    //ret = texture(sampler_main, vUv).xyz;
    //ret = diffuse;
    ret = point_falloff * diffuse;
    //if(non_ave > 0.5) {ret = nonHeight * 0.33333331;}
    //if(vUv.x > vUv.y){ret = diffuse;}

  fragColor = ret;
}
